from sqlalchemy.orm import Session
from .models import Url

class UrlRepo:
    def __init__(self, db: Session):
        self.db = db

    def insert(self, slug: str, target: str) -> Url:
        url = Url(slug=slug, target=target)
        self.db.add(url)
        self.db.commit()
        return url

    def find_by_slug(self, slug: str) -> Url | None:
        return self.db.query(Url).filter(Url.slug == slug).first()

    def increment_click(self, slug: str) -> int:
        url = self.find_by_slug(slug)
        if url is None:
            return 0
        url.click_count += 1
        self.db.commit()
        return url.click_count

