class FakeSession:
    def __init__(self):
        self.added = []
        self.committed = False
    def add(self, x): self.added.append(x)
    def commit(self): self.committed = True
    def query(self, _): raise NotImplementedError("only used for write paths in this test")

def test_insert_persists_url():
    repo = UrlRepo(FakeSession())
    url = repo.insert("ab1234", "https://example.com")
    assert url.slug == "ab1234"
    assert url.target == "https://example.com"
    assert repo.db.committed is True
    assert repo.db.added == [url]

