import pytest
from services.url_service import UrlService

class FakeRepo:
    def __init__(self):
        self.urls = {}
    def find_by_slug(self, slug):
        return self.urls.get(slug)
    def insert(self, slug, target):
        u = type("U", (), {"slug": slug, "target": target, "click_count": 0})()
        self.urls[slug] = u
        return u

def test_create_returns_six_char_slug():
    svc = UrlService(FakeRepo())
    out = svc.create("https://example.com")
    assert len(out.slug) == 6

def test_resolve_unknown_returns_none():
    svc = UrlService(FakeRepo())
    assert svc.resolve("nope") is None

def test_create_retries_on_collision():
    repo = FakeRepo()
    repo.urls["ab1234"] = "preexisting"
    svc = UrlService(repo)
    out = svc.create("https://x.com")
    assert out.slug != "ab1234"

from fastapi import FastAPI, HTTPException
from fastapi.responses import RedirectResponse
from services.url_service import UrlService

app = FastAPI()

@app.post("/shorten")
async def shorten(target: str, svc: UrlService):
    url = svc.create(target)
    return {"slug": url.slug}

@app.get("/{slug}")
async def resolve(slug: str, svc: UrlService):
    url = svc.resolve(slug)
    if url is None:
        raise HTTPException(404)
    svc.repo.increment_click(slug)
    return RedirectResponse(url.target, status_code=302)

